using System.Linq;

class CosmosQuery
{
    // EF Core 9 Cosmos: sync I/O (ToList, SaveChanges, etc.) now throws.
    // All queries must use async equivalents.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we preserved "Discriminator"
        // via HasDiscriminator<string>("Discriminator") in OnModelCreating.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // Replaced ToList() with ToListAsync() — sync I/O is no longer supported.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

